// SPDX-License-Identifier: Elastic-2.0
package passwd

import "testing"

func TestValid(t *testing.T) {
	cases := []struct {
		name string
		pw   string
		want bool
	}{
		{
			name: "valid password with all classes and length 12",
			pw:   "Aa1!Aa1!Aa1!",
			want: true,
		},
		{
			// length 11 with all classes present.
			// A mutant that only checks len < 8 (instead of len < 12)
			// would incorrectly accept this.
			name: "too short (11 chars) with all classes must fail",
			pw:   "Aa1!Bb2@Cc3",
			want: false,
		},
		{
			// length 12, has upper/lower/digit but no symbol.
			// A mutant that forces the symbol flag to true regardless
			// of actual content would incorrectly accept this.
			name: "length 12 missing symbol must fail",
			pw:   "Aa1Bb2Cc3Dd4",
			want: false,
		},
		{
			// length 12, only digits (no letters at all, no symbol).
			// A mutant using OR instead of AND across the four
			// character-class flags would incorrectly accept this,
			// since the digit flag alone would satisfy an OR check.
			name: "length 12 only digits must fail",
			pw:   "123456789012",
			want: false,
		},
		{
			// sanity check: missing digit should fail even though
			// upper/lower/symbol are all present and length is sufficient.
			name: "missing digit must fail",
			pw:   "Aa!Aa!Aa!Aa!",
			want: false,
		},
	}

	for _, c := range cases {
		t.Run(c.name, func(t *testing.T) {
			got := Valid(c.pw)
			if got != c.want {
				t.Errorf("Valid(%q) = %v, want %v", c.pw, got, c.want)
			}
		})
	}
}
